module ieee754_example;
    // IEEE 754 Single Precision structure
    reg [31:0] float_num;

    // Extract fields
    wire sign;
    wire [7:0] exponent;
    wire [22:0] mantissa;

    assign sign = float_num[31];
    assign exponent = float_num[30:23];
    assign mantissa = float_num[22:0];

    initial begin
        // Example: 13.625 = 0x4159A000
        float_num = 32'h4159A000;

        $display("IEEE 754 Analysis:");
        $display("Float value (hex): 0x%h", float_num);
        $display("Sign: %b (%s)", sign, sign ? "negative" : "positive");
        $display("Exponent: %b = %d (actual: %d)", 
                 exponent, exponent, exponent - 127);
        $display("Mantissa: %b", mantissa);

        // Some special values
        float_num = 32'h7F800000;  // +Infinity
        $display("\n+Infinity: 0x%h", float_num);

        float_num = 32'hFF800000;  // -Infinity  
        $display("-Infinity: 0x%h", float_num);

        float_num = 32'h7FC00000;  // NaN
        $display("NaN: 0x%h", float_num);
    end
endmodule
